const webhook = $('Webhook').first().json;
const webhookData = webhook.body || webhook || {};
let raw = [];
try {
  raw = $('MongoDB — Buscar plantilla').first().json;
} catch (e) {
  raw = [];
}
const tmpl = (Array.isArray(raw) && raw.length > 0) ? raw[0] : (raw && Object.keys(raw).length > 0 ? raw : null);

const parameters = webhookData.parameters || {};
const companyName = webhookData.company_name_val || webhookData.company_name || 'Empresa Auditada';
const reportId = webhookData.report_id || ('CS-RPT-' + new Date().toISOString().slice(0,10) + '-' + webhookData.attack_id);

const name = tmpl ? tmpl.name : webhookData.attack_name;
const mitre_id = tmpl ? tmpl.mitre_id : webhookData.mitre_id;
const risk_level = tmpl ? tmpl.risk_level : webhookData.risk_level;
const wazuh_rule_id = tmpl ? tmpl.wazuh_rule_id : webhookData.wazuh_rule_id;
const description = tmpl ? tmpl.description : webhookData.description;

let command = (tmpl ? tmpl.command : '') || webhookData.command;
let logger_command = (tmpl ? tmpl.logger_command : '') || webhookData.logger_command;

// Reemplazo dinamico de parámetros en n8n como salvaguarda
if (command && parameters) {
  for (const key in parameters) {
    const val = parameters[key];
    command = command.replace(new RegExp('{{' + key + '}}', 'g'), val || '');
  }
}
if (logger_command && parameters) {
  for (const key in parameters) {
    const val = parameters[key];
    logger_command = logger_command.replace(new RegExp('{{' + key + '}}', 'g'), val || '');
  }
}

return [{ 
  json: {
    attack_id: webhookData.attack_id,
    attack_name: name,
    mitre_id: mitre_id,
    risk_level: risk_level,
    wazuh_rule_id: wazuh_rule_id,
    description: description,
    command: command,
    logger_command: logger_command,
    parameters: parameters,
    company_name: companyName,
    report_id: reportId,
    start_timestamp: new Date().toISOString()
  }
}];
